<?php require_once __DIR__.'/../../backend/shared/auth.php'; require_role('doctor'); require_once __DIR__.'/../../backend/shared/ai_engine.php'; require_once __DIR__.'/../../backend/shared/layout.php';
$hn=$_GET['hn']??''; if(isset($_GET['run_all'])){$ids=db()->query('SELECT id FROM patients')->fetchAll(PDO::FETCH_COLUMN); foreach($ids as $id) save_ai_risk((int)$id); header('Location: ai-risk.php?done=all'); exit;}
if($hn && isset($_GET['run'])){$st=db()->prepare('SELECT id FROM patients WHERE hn=?');$st->execute([$hn]);$id=$st->fetchColumn(); if($id) save_ai_risk((int)$id);}
$rows=db()->query('SELECT p.hn,p.first_name,p.last_name,a.* FROM ai_risk_assessments a JOIN patients p ON p.id=a.patient_id JOIN (SELECT patient_id,MAX(id) mid FROM ai_risk_assessments GROUP BY patient_id) x ON x.mid=a.id ORDER BY a.score DESC LIMIT 50')->fetchAll();
app_header('AI Risk Engine','doctor','ai'); ?><a class="back" href="dashboard.php">← กลับ Dashboard</a><div class="card"><div class="tl-head"><div><h3>AI วิเคราะห์เบาหวาน/ความดันจากข้อมูลจริงใน MySQL</h3><p class="tl-meta">ใช้ HbA1c, FPG, BMI, SBP/DBP, eGFR, UACR, LDL และโรคร่วม</p></div><a class="btn" href="?run_all=1">วิเคราะห์ผู้ป่วยทั้งหมด 100 คน</a></div><form><div class="row"><div class="field"><input name="hn" placeholder="HN000001"></div><div class="field"><button class="btn secondary" name="run" value="1">วิเคราะห์ HN นี้</button></div></div></form></div><div class="card" style="margin-top:18px"><h3>ผลล่าสุด</h3><div class="table-wrap"><table class="table"><tr><th>HN</th><th>ชื่อ</th><th>Score</th><th>Level</th><th>เหตุผล</th><th>คำแนะนำ</th></tr><?php foreach($rows as $r):?><tr><td><?=e($r['hn'])?></td><td><?=e($r['first_name'].' '.$r['last_name'])?></td><td><b><?=$r['score']?></b></td><td><span class="badge <?=$r['level']==='High'?'red':($r['level']==='Moderate'?'warn':'')?>"><?=e($r['level'])?></span></td><td><?=e(str_replace(['[',']','"'], '', $r['reasons']))?></td><td><?=e($r['recommendation'])?></td></tr><?php endforeach;?></table></div></div><?php app_footer();?>
